def main() -> None:
    init_db()
    existing = {item["input_text"].lower() for item in list_vocab()}
    added = 0
    for item in SAMPLE_VOCAB:
        if item["input_text"].lower() in existing:
            continue
        create_vocab(VocabCreate(**item))
        added += 1
    print(f"Seed complete. Added {added} sample vocabulary item(s). Total sample list size: {len(SAMPLE_VOCAB)}.")


if __name__ == "__main__":
    main()
